import React, { useState, useEffect } from 'react';
import styled from 'styled-components'
import { useHistory,useParams } from 'react-router-dom';
import './Detail.scss';



let 박스 = styled.div`
padding : 20px;
`;
let 제목 = styled.h4`
  font-size : 25px;
  color : ${ props => props.color };
`;

function Detail(props){

  let [ alert, alert변경 ] = useState(true);
  let [inputData, inputData변경] = useState('');


    useEffect(()=>{ 
      let 타이머 = setTimeout(()=>{ alert변경(false) }, 2000);

      return ()=>{ clearTimeout(타이머) }
    },[alert] );

    let history = useHistory();
    let { id } = useParams();
    let itemId= props.shoes.find(x => x.id == id);

    return (
      <div className="container">
        <박스>
            <제목 className='red'>세부설명</제목>
        </박스>

        { 
      alert === true 
      ? (<div className="my-alert2"> 
          <p>재고가 얼마 남지 않았습니다</p> 
      </div>) 
     : null 
        }
        <div className="row">
          <div className="col-md-6">
            <img src={ 'https://codingapple1.github.io/shop/shoes' + (itemId.id+1) + '.jpg' }width="100%" />
          </div>
          <div className="col-md-6 mt-4">
            <h4 className="pt-5">{itemId.title }</h4>
            <p>{itemId.content }</p>
            <p>{itemId.price } 원 </p>

            <Info 재고={props.재고}></Info>

            <button className="btn btn-danger mr-5" onClick={ () => {props.재고변경([9,11,12])} }>주문하기</button> 
            <button onClick={()=>{ history.push('/') }} className="btn btn-danger">뒤로가기</button> 
          </div>
        </div>


    </div>  
    )
  };

  function Info(props){
    return (
      <p> 재고 : {props.재고[0]} </p>
    )
  }
  
  export default Detail 