import './App.css';
import { Navbar,Container,Nav,NavDropdown, } from 'react-bootstrap';
import React, {useState} from 'react';
import shoesData from './data.js';
import { Link, Route, Switch } from 'react-router-dom';
import Detail from './Detail.js';
import axios from 'axios';
import styled from 'styled-components';
import Spinner from './loading'



function App() {

  let [shoes, shoes변경] = useState(shoesData);
  let [plus, plus변경] = useState(true);
  const [loading, setLoading] = useState(false);
  const [재고, 재고변경] = useState([10, 11, 12]);

  return (
    <div className="App">
      <Navbar bg="light" expand="lg">
        <Container>
          <Navbar.Brand href="#home">React-Bootstrap</Navbar.Brand>
          <Navbar.Toggle aria-controls="basic-navbar-nav" />
          <Navbar.Collapse id="basic-navbar-nav">
            <Nav className="me-auto">
              <Nav.Link> <Link to="/">Home</Link> </Nav.Link>
              <Nav.Link><Link to="/detail">Detail</Link></Nav.Link>
              <NavDropdown title="Dropdown" id="basic-nav-dropdown">
                <NavDropdown.Item href="#action/3.1">Action</NavDropdown.Item>
                <NavDropdown.Item href="#action/3.2">Another action</NavDropdown.Item>
                <NavDropdown.Item href="#action/3.3">Something</NavDropdown.Item>
                <NavDropdown.Divider />
                <NavDropdown.Item href="#action/3.4">Separated link</NavDropdown.Item>
              </NavDropdown>
            </Nav>
          </Navbar.Collapse>
        </Container>
      </Navbar>

      <Switch>
        <Route exact path="/"> 
      
            <div className='background'>
              <div className='background-content'>
              <p>멋진 신발을 구경하세요</p>
              <a name="" id="" class="btn btn-primary bg-button" href="#" role="button">구입하기</a>
              </div>
            </div>
            <div className="container">
            <div className="row">

            {
            loading == true ?

            <Spinner />
            :null

          }
              {
                shoes.map((a,i)=>{
                  return <Item shoes={shoes[i]} i={i} key={i}/>
                })
              }
            </div>

          {
            plus == true ? 
            <button className="btn btn-primary" onClick={()=>{
              
              setLoading(true);
   
              axios.get('https://codingapple1.github.io/shop/data2.json')
              .then( result =>{
                
                 shoes변경([...shoes, ...result.data ]);
                 plus변경('false');
                 setLoading(false);
                })
              .catch(()=>{ alert('데이터를 불러오지 못했습니다.') })

              }}>더보기</button>

              : null
          }


          </div>

        </Route>

        <Route path="/detail/:id">
          <Detail shoes={shoes} 재고={재고} 재고변경={재고변경}/>
        </Route>

        <Route path="/:id">
            <div>새로 만든 route입니다</div>
        </Route>

      </Switch>

     
     
    </div>
  );
}


function Item(props){
  return (
    <div className="col-md-4">
    <img src={'https://codingapple1.github.io/shop/shoes' + (props.i+1) + '.jpg'} width="100%" />
    <h4> { props.shoes.title } </h4>
    <p> { props.shoes.price } </p>
  </div>
  )
}



export default App;
